// Normalize Smart Publish Request: nhận input từ AI Agent wf01, validate và chuẩn hóa.
const item = $input.first().json;
const body = item.body || item;
let params = body.params || body;

// CASE A: AI tool truyền JSON string trong field 'query' (default của toolWorkflow khi sub-workflow trigger là executeWorkflowTrigger).
// ToolWorkflowV1 ở @n8n/n8n-nodes-langchain wrap toàn bộ function call args thành { json: { query: '<json string>' } }.
if (item.query && typeof item.query === 'string') {
  try { params = JSON.parse(item.query); }
  catch (e) { return [{ json: { success: false, chat_id: String(item.chat_id || $env.ADMIN_TELEGRAM_CHAT_ID || ''), error_message: 'Query JSON không hợp lệ từ tool call: ' + e.message } }]; }
}
// CASE B: body hoặc params có thể là string JSON (khi gọi qua Execute Workflow node).
if (typeof params === 'string') {
  try { params = JSON.parse(params); } catch (e) { params = {}; }
}
if (typeof body === 'string') {
  try { body = JSON.parse(body); } catch (e) { body = {}; }
}
// CASE C: ToolWorkflow v2 (@n8n/n8n-nodes-langchain.toolWorkflow typeVersion 2) truyền LLM function call args
// thành các field top-level trực tiếp trên item (vd: item.mode, item.media_kind, item.photo_file_id, ...).
// Detect: nếu item có bất kỳ field smart-publisher nào ở top-level thì gộp vào params.
const toolFields = ['mode', 'media_kind', 'mediaKind', 'photo_file_id', 'photoFileId', 'video_file_id', 'videoFileId', 'user_caption', 'userCaption', 'caption', 'content', 'user_prompt', 'userPrompt', 'topic', 'image_url', 'imageUrl', 'video_url', 'videoUrl', 'chat_id', 'chatId', 'target_page', 'targetPage', 'platform', 'tone', 'language'];
if (!params || typeof params !== 'object' || Array.isArray(params) || Object.keys(params).length === 0) {
  const merged = {};
  let hasToolField = false;
  for (const f of toolFields) {
    if (item[f] !== undefined && item[f] !== null && item[f] !== '') {
      merged[f] = item[f];
      hasToolField = true;
    }
  }
  if (hasToolField) {
    params = merged;
  }
}
if (!params || typeof params !== 'object' || Array.isArray(params) || Object.keys(params).length === 0) {
  params = (body && typeof body === 'object' && !Array.isArray(body)) ? body : {};
}

const mode = String(params.mode || 'ai').toLowerCase();
if (!['ai', 'manual'].includes(mode)) {
  return [{ json: { success: false, chat_id: params.chat_id || $env.ADMIN_TELEGRAM_CHAT_ID || '', error_message: 'mode không hợp lệ. Chỉ chấp nhận "ai" hoặc "manual".' } }];
}

const mediaKindRaw = String(params.media_kind || params.mediaKind || 'text').toLowerCase();
let mediaKind = 'text';
if (['image', 'photo', 'img', 'picture'].includes(mediaKindRaw)) mediaKind = 'image';
else if (['video', 'clip', 'reel', 'mp4'].includes(mediaKindRaw)) mediaKind = 'video';
else mediaKind = 'text';

const photoFileId = String(params.photo_file_id || params.photoFileId || '');
const videoFileId = String(params.video_file_id || params.videoFileId || '');
const userCaption = String(params.user_caption || params.userCaption || params.caption || params.content || '');
const userPrompt = String(params.user_prompt || params.userPrompt || params.topic || userCaption || '');
const imageUrl = String(params.image_url || params.imageUrl || '');
const videoUrl = String(params.video_url || params.videoUrl || '');
const chatId = String(params.chat_id || params.chatId || $env.ADMIN_TELEGRAM_CHAT_ID || '');
const targetPage = String(params.target_page || params.targetPage || 'default');
const platform = String(params.platform || 'facebook').toLowerCase();
const tone = String(params.tone || 'friendly').toLowerCase();
const language = String(params.language || 'vi').toLowerCase();

// LENIENT FALLBACK: nếu mode=ai mà thiếu user_prompt, tự generate từ context
let effectiveUserPrompt = userPrompt.trim();
if (mode === 'ai' && !effectiveUserPrompt) {
  // Fallback 1: dùng user_caption nếu có
  if (userCaption.trim()) {
    effectiveUserPrompt = userCaption.trim();
  }
  // Fallback 2: dùng media_kind làm prompt
  else if (mediaKind === 'image' && photoFileId) {
    effectiveUserPrompt = 'Bài đăng về sản phẩm thời trang trong ảnh';
  }
  else if (mediaKind === 'video' && videoFileId) {
    effectiveUserPrompt = 'Bài đăng về video sản phẩm thời trang';
  }
  // Fallback 3: generic
  else {
    effectiveUserPrompt = 'Bài đăng fanpage thời trang';
  }
}

// Validate: chỉ fail khi cả 2 mode đều không có gì để làm
if (mode === 'manual' && !userCaption.trim() && !effectiveUserPrompt) {
  return [{ json: { success: false, chat_id: chatId, error_message: 'Thiếu nội dung caption (user_caption) cho chế độ manual.' } }];
}

// Validate chat_id
if (!chatId) {
  return [{ json: { success: false, chat_id: '', error_message: 'Thiếu chat_id. Hãy truyền chat_id từ $json.chat_id của Telegram trigger.' } }];
}

// Effective kind fallback
let effectiveKind = mediaKind;
if (mode === 'ai' && mediaKind === 'image' && !photoFileId && !imageUrl) {
  effectiveKind = 'text';
}
if (mode === 'ai' && mediaKind === 'video' && !videoFileId && !videoUrl) {
  effectiveKind = 'text';
}

return [{
  json: {
    success: true,
    mode,
    media_kind: mediaKind,
    effective_kind: effectiveKind,
    photo_file_id: photoFileId,
    video_file_id: videoFileId,
    image_url: imageUrl,
    video_url: videoUrl,
    user_caption: userCaption,
    user_prompt: effectiveUserPrompt,
    chat_id: chatId,
    target_page: targetPage,
    platform,
    tone,
    language
  }
}];

// Build error payload when photo_file_id is missing in ai|image mode
const norm = $node['Normalize Smart Publish Request'].json || $json;
return [{ json: {
  success: false,
  chat_id: norm.chat_id || $env.ADMIN_TELEGRAM_CHAT_ID || '',
  error_message: 'Thiếu photo_file_id cho mode ai|image. Vui lòng gửi ảnh kèm theo.'
} }];

// Build error payload when video_file_id is missing in ai|video mode
const norm = $node['Normalize Smart Publish Request'].json || $json;
return [{ json: {
  success: false,
  chat_id: norm.chat_id || $env.ADMIN_TELEGRAM_CHAT_ID || '',
  error_message: 'Thiếu video_file_id cho mode ai|video. Vui lòng gửi video kèm theo.'
} }];

// Build Gemini 3.1 Flash Lite Vision request for photo analysis + caption generation
const norm = $node['Normalize Smart Publish Request'].json;
const chatId = norm.chat_id;

// Resolve binary from previous download
const binaryKey = Object.keys($input.first().binary || {})[0] || 'data';
const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
const photoBase64 = buffer.toString('base64');

let photoMime = 'image/jpeg';
if (photoBase64.startsWith('/9j/')) photoMime = 'image/jpeg';
else if (photoBase64.startsWith('iVBOR')) photoMime = 'image/png';
else if (photoBase64.startsWith('R0lG')) photoMime = 'image/gif';
else if (photoBase64.startsWith('UklG')) photoMime = 'image/webp';

if (!photoBase64 || photoBase64.length < 100) {
  return [{ json: { success: false, chat_id: chatId, error_message: 'Binary ảnh rỗng hoặc không hợp lệ.' } }];
}

const toneMap = {
  friendly: 'thân thiện, gần gũi, dùng nhiều emoji',
  luxury:   'sang trọng, tinh tế, tối giản emoji',
  casual:   'trẻ trung, năng động, thoải mái',
  urgent:   'cấp bách, khuyến mãi, có cảm giác FOMO'
};
const toneDesc = toneMap[norm.tone] || toneMap.friendly;
const langMap = { vi: 'tiếng Việt', en: 'tiếng Anh' };
const langDesc = langMap[norm.language] || 'tiếng Việt';

const systemPrompt = `Bạn là copywriter chuyên nghiệp cho fanpage Facebook thời trang Việt Nam.\n\n` +
`Nhiệm vụ: Phân tích hình ảnh sản phẩm được đính kèm và viết caption bằng ${langDesc} phù hợp để đăng lên Facebook Fanpage.\n\n` +
`Yêu cầu:\n` +
`- Tone: ${toneDesc}\n` +
`- Caption: 2-4 câu, có cảm xúc, có hook mở đầu thu hút\n` +
`- Có 1-2 emoji phù hợp (không lạm dụng)\n` +
`- 3-6 hashtag liên quan (mix tiếng Việt + tiếng Anh nếu phù hợp)\n` +
`- 1 câu call-to-action rõ ràng (CTA)\n` +
`${norm.user_prompt ? 'Bối cảnh thêm từ người dùng: ' + norm.user_prompt : ''}\n\n` +
`Trả về JSON hợp lệ theo schema.`;

const geminiBody = {
  contents: [{
    parts: [
      { text: systemPrompt },
      { inlineData: { mimeType: photoMime, data: photoBase64 } }
    ]
  }],
  generationConfig: {
    responseMimeType: 'application/json',
    responseSchema: {
      type: 'object',
      properties: {
        caption:  { type: 'string', description: 'Caption chính, 2-4 câu' },
        hashtags: { type: 'array',  items: { type: 'string' } },
        cta:      { type: 'string', description: 'Call-to-action ngắn' },
        tone:     { type: 'string', enum: ['friendly', 'luxury', 'casual', 'urgent'] }
      },
      required: ['caption', 'hashtags']
    }
  }
};

return [{
  json: {
    gemini_body: geminiBody,
    chat_id: chatId,
    mode: 'ai',
    media_kind: 'image',
    photo_file_id: norm.photo_file_id,
    image_url: norm.image_url,
    target_page: norm.target_page,
    platform: norm.platform,
    source: 'gemini-vision-photo'
  }
}];

// Build Gemini Vision body for VIDEO
const norm = $node['Normalize Smart Publish Request'].json;
const chatId = norm.chat_id;

const binaryKey = Object.keys($input.first().binary || {})[0] || 'data';
const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
const videoBase64 = buffer.toString('base64');

// Guess mime from base64 header (mp4/webm/mov)
let videoMime = 'video/mp4';
if (videoBase64.startsWith('AAAA')) videoMime = 'video/mp4';
else if (videoBase64.startsWith('GkX')) videoMime = 'video/webm';

if (!videoBase64 || videoBase64.length < 200) {
  return [{ json: { success: false, chat_id: chatId, error_message: 'Binary video rỗng.' } }];
}

const toneMap = {
  friendly: 'thân thiện, gần gũi',
  luxury:   'sang trọng, tinh tế',
  casual:   'trẻ trung, năng động',
  urgent:   'cấp bách, FOMO'
};
const toneDesc = toneMap[norm.tone] || toneMap.friendly;
const langDesc = norm.language === 'en' ? 'tiếng Anh' : 'tiếng Việt';

const systemPrompt = `Bạn là copywriter chuyên video ngắn (Reels/TikTok) cho fanpage Facebook thời trang Việt Nam.\n\n` +
`Nhiệm vụ: Phân tích video ngắn được đính kèm và viết caption bằng ${langDesc}.\n\n` +
`Yêu cầu:\n` +
`- Tone: ${toneDesc}\n` +
`- Caption: 2-3 câu ngắn gọn, mạnh, có hook\n` +
`- 3-6 hashtag (mix #Reels #FYP nếu phù hợp)\n` +
`- 1 CTA: "Xem chi tiết", "Đặt hàng ngay"...\n` +
`${norm.user_prompt ? 'Bối cảnh: ' + norm.user_prompt : ''}\n\n` +
`Trả về JSON hợp lệ theo schema.`;

const geminiBody = {
  contents: [{
    parts: [
      { text: systemPrompt },
      { inlineData: { mimeType: videoMime, data: videoBase64 } }
    ]
  }],
  generationConfig: {
    responseMimeType: 'application/json',
    responseSchema: {
      type: 'object',
      properties: {
        caption:  { type: 'string' },
        hashtags: { type: 'array', items: { type: 'string' } },
        cta:      { type: 'string' },
        tone:     { type: 'string', enum: ['friendly', 'luxury', 'casual', 'urgent'] }
      },
      required: ['caption', 'hashtags']
    }
  }
};

return [{
  json: {
    gemini_body: geminiBody,
    chat_id: chatId,
    mode: 'ai',
    media_kind: 'video',
    video_file_id: norm.video_file_id,
    video_url: norm.video_url,
    target_page: norm.target_page,
    platform: norm.platform,
    source: 'gemini-vision-video'
  }
}];

// Build Gemini text-only body for caption generation from topic
const norm = $node['Normalize Smart Publish Request'].json;

const toneMap = {
  friendly: 'thân thiện, gần gũi, nhiều emoji',
  luxury:   'sang trọng, tinh tế, tối giản',
  casual:   'trẻ trung, thoải mái',
  urgent:   'cấp bách, FOMO, khuyến mãi'
};
const toneDesc = toneMap[norm.tone] || toneMap.friendly;
const langDesc = norm.language === 'en' ? 'tiếng Anh' : 'tiếng Việt';

const systemPrompt = `Bạn là copywriter chuyên nghiệp cho fanpage Facebook thời trang Việt Nam.\n\n` +
`Nhiệm vụ: Viết caption bằng ${langDesc} dựa trên chủ đề/chủ đề người dùng cung cấp.\n\n` +
`Chủ đề: "${norm.user_prompt}"\n\n` +
`Yêu cầu:\n` +
`- Tone: ${toneDesc}\n` +
`- Caption: 2-4 câu, có hook mở đầu\n` +
`- 3-6 hashtag liên quan\n` +
`- 1 call-to-action rõ ràng\n\n` +
`Trả về JSON hợp lệ theo schema.`;

const geminiBody = {
  contents: [{ parts: [{ text: systemPrompt }] }],
  generationConfig: {
    responseMimeType: 'application/json',
    responseSchema: {
      type: 'object',
      properties: {
        caption:  { type: 'string' },
        hashtags: { type: 'array', items: { type: 'string' } },
        cta:      { type: 'string' },
        tone:     { type: 'string', enum: ['friendly', 'luxury', 'casual', 'urgent'] }
      },
      required: ['caption', 'hashtags']
    }
  }
};

return [{
  json: {
    gemini_body: geminiBody,
    chat_id: norm.chat_id,
    mode: 'ai',
    media_kind: 'text',
    target_page: norm.target_page,
    platform: norm.platform,
    user_prompt: norm.user_prompt,
    source: 'gemini-text'
  }
}];

// Manual mode: build preview payload from user_caption directly
const norm = $node['Normalize Smart Publish Request'].json;
const caption = norm.user_caption.trim();

if (!caption) {
  return [{ json: { success: false, chat_id: norm.chat_id, error_message: 'Caption trống ở mode manual.' }}];
}

return [{ json: {
  success: true,
  chat_id: norm.chat_id,
  mode: 'manual',
  media_kind: norm.media_kind,
  effective_kind: norm.effective_kind,
  caption: caption,
  raw_caption: caption,
  hashtags: [],
  cta: '',
  photo_file_id: norm.photo_file_id,
  video_file_id: norm.video_file_id,
  image_url: norm.image_url,
  video_url: norm.video_url,
  target_page: norm.target_page,
  platform: norm.platform,
  source: 'manual'
}}];

// Unified Gemini response parser - handles all 3 modes (image/video/text) the same way
const req = $node['Call Gemini 3.1 Flash Lite'].json;
const reqBody = $input.first().json;
const builder = $('Build Gemini Vision Body (Image), Build Gemini Vision Body (Video), Build Gemini Text Body').first()?.json || req;

try {
  const res = $input.first().json;
  const firstCandidate = res.candidates?.[0];
  const finishReason = firstCandidate?.finishReason || firstCandidate?.finish_reason;

  if (finishReason === 'SAFETY') {
    return [{ json: {
      success: false,
      chat_id: (builder && builder.chat_id) || '',
      error_message: '⚠️ Gemini từ chối phân tích do bộ lọc an toàn. Vui lòng dùng ảnh/video khác hoặc chuyển sang mode manual.'
    }}];
  }

  const textPart = firstCandidate?.content?.parts?.find(p => p.text);
  const rawText = textPart?.text || '';
  if (!rawText) {
    return [{ json: {
      success: false,
      chat_id: (builder && builder.chat_id) || '',
      error_message: 'Gemini không trả về nội dung.'
    }}];
  }

  let parsed;
  try { parsed = JSON.parse(rawText); }
  catch {
    parsed = { caption: rawText, hashtags: [], cta: '' };
  }

  const caption = (parsed.caption || '').trim();
  const hashtags = Array.isArray(parsed.hashtags) ? parsed.hashtags : [];
  const cta = (parsed.cta || '').trim();
  const tone = parsed.tone || 'friendly';

  const fullCaption = [caption, hashtags.length ? '\n\n' + hashtags.map(h => h.startsWith('#') ? h : '#' + h).join(' ') : '', cta ? '\n\n👉 ' + cta : ''].join('').trim();

  if (!caption) {
    return [{ json: {
      success: false,
      chat_id: (builder && builder.chat_id) || '',
      error_message: 'Caption rỗng sau khi parse Gemini.'
    }}];
  }

  return [{ json: {
    success: true,
    chat_id: (builder && builder.chat_id) || '',
    mode: 'ai',
    media_kind: (builder && builder.media_kind) || 'text',
    caption: fullCaption,
    raw_caption: caption,
    hashtags,
    cta,
    tone,
    photo_file_id: (builder && builder.photo_file_id) || '',
    video_file_id: (builder && builder.video_file_id) || '',
    image_url: (builder && builder.image_url) || '',
    video_url: (builder && builder.video_url) || '',
    target_page: (builder && builder.target_page) || 'default',
    platform: (builder && builder.platform) || 'facebook',
    source: (builder && builder.source) || 'ai-vision'
  }}];
} catch (err) {
  return [{ json: {
    success: false,
    chat_id: (builder && builder.chat_id) || '',
    error_message: 'Lỗi parse Gemini response: ' + (err.message || String(err))
  }}];
}

// Build preview message and approval_id, persist to static data
// Fix: atomic write (no race condition) + TTL 24h + dedup-safe UUID
const payload = $input.first().json;

// Nhánh lỗi: không tạo approval_id, trả về payload error
if (payload.success === false) {
  return [{ json: { ...payload, _branch: 'error' } }];
}

const chatId = String(payload.chat_id || $env.ADMIN_TELEGRAM_CHAT_ID || '');
const mediaKind = payload.media_kind || payload.effective_kind || 'text';

// FIX 3: Use crypto.randomUUID for collision-free ID (instead of Date.now which can collide on concurrent calls)
let approvalId;
try {
  const crypto = require('crypto');
  approvalId = 'FSP-' + crypto.randomUUID().slice(0, 8).toUpperCase();
} catch (e) {
  // Fallback if crypto unavailable
  approvalId = 'FSP-' + Date.now().toString(36).toUpperCase() + '-' + Math.random().toString(36).slice(2, 6).toUpperCase();
}

let fs = null, path = null;
try { fs = require('fs'); path = require('path'); } catch (e) {}

const filePath = path ? path.join($env.N8N_USER_FOLDER || './.n8n', 'pending_smart_publish.json') : null;
const now = Date.now();
const TTL_MS = 24 * 60 * 60 * 1000; // 24 hours

// Load or init store, prune expired
let store = { pendingApprovals: {} };
if (filePath && fs && fs.existsSync(filePath)) {
  try {
    store = JSON.parse(fs.readFileSync(filePath, 'utf8'));
    store.pendingApprovals = store.pendingApprovals || {};
    // FIX 7: Prune expired approvals to prevent file bloat
    for (const [id, rec] of Object.entries(store.pendingApprovals)) {
      if (rec.expiry_at && new Date(rec.expiry_at).getTime() < now) {
        delete store.pendingApprovals[id];
      }
    }
  } catch (e) {
    // Corrupt file - start fresh, keep old as backup
    try { fs.writeFileSync(filePath + '.corrupt.' + now, fs.readFileSync(filePath, 'utf8')); } catch (e2) {}
    store = { pendingApprovals: {} };
  }
}

const expiryAt = new Date(now + TTL_MS).toISOString();

// Store full payload for later use by 06_Social_Publisher
store.pendingApprovals[approvalId] = {
  ...payload,
  approval_id: approvalId,
  chat_id: chatId,           // FIX: explicit ownership field for cross-check
  media_kind: mediaKind,
  created_at: new Date(now).toISOString(),
  expiry_at: expiryAt
};

// FIX 4: Atomic write - write to .tmp then rename to prevent partial reads
if (filePath && fs) {
  try {
    fs.mkdirSync(path.dirname(filePath), { recursive: true });
    const tmpPath = filePath + '.tmp';
    fs.writeFileSync(tmpPath, JSON.stringify(store, null, 2), 'utf8');
    fs.renameSync(tmpPath, filePath);
  } catch (e) {
    // Last-resort: log but don't fail the workflow
    // (preview will still be sent; approval is best-effort persistence)
  }
}

return [{ json: {
  ...payload,
  approval_id: approvalId,
  chat_id: chatId,
  media_kind: mediaKind,
  expiry_at: expiryAt,
  _branch: 'success'
} }];
